     1→import React, { useCallback, useEffect, useRef, useState } from "react";
     2→import { useQueryClient } from "@tanstack/react-query";
     3→import { useAuth } from "../../../Context/useAuth";
     4→import { updateProfileLayout } from "../../../../API/Api";
     5→import {
     6→    MAX_NOTES_COUNT,
     7→    DEFAULT_NOTE_CONTAINER_STYLE,
     8→    DEFAULT_PROFILE_LAYOUT,
     9→} from "../../../utils/profileLayout/constants";
    10→import NoteContainer from "./NoteContainer";
    11→import "./notesSection.css";
    12→
    13→const ProfileNotesSection = ({ notes: initialNotes, isOwner, userData, expandInnerContainerOnClick = false }) => {
    14→    const [notes, setNotes] = useState(initialNotes || []);
    15→    const [isSaving, setIsSaving] = useState(false);
    16→    const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
    17→    const hasUnsavedChangesRef = useRef(false);
    18→    const { session } = useAuth();
    19→    const queryClient = useQueryClient();
    20→
    21→    useEffect(() => {
    22→        hasUnsavedChangesRef.current = hasUnsavedChanges;
    23→    }, [hasUnsavedChanges]);
    24→
    25→    useEffect(() => {
    26→        if (hasUnsavedChangesRef.current) return;
    27→        setNotes(initialNotes || []);
    28→        setHasUnsavedChanges(false);
    29→    }, [initialNotes]);
    30→
    31→    const saveNotes = useCallback(
    32→        async (updatedNotes) => {
    33→            if (!session?.access_token || !userData) return;
    34→
    35→            setIsSaving(true);
    36→            try {
    37→                const baseLayout = userData.profile_layout || DEFAULT_PROFILE_LAYOUT;
    38→                const newLayout = {
    39→                    ...baseLayout,
    40→                    notes: updatedNotes,
    41→                };
    42→                await updateProfileLayout(session.access_token, newLayout);
    43→                queryClient.invalidateQueries({ queryKey: ["userData"] });
    44→                return true;
    45→            } catch (err) {
    46→                console.error("Failed to save notes:", err);
    47→                return false;
    48→            } finally {
    49→                setIsSaving(false);
    50→            }
    51→        },
    52→        [session, userData, queryClient]
    53→    );
    54→
    55→    const handleAddNote = () => {
    56→        if (notes.length >= MAX_NOTES_COUNT) return;
    57→
    58→        const newNote = {
    59→            id: `note_${crypto.randomUUID()}`,
    60→            order: notes.length,
    61→            content: null,
    62→            containerStyle: { ...DEFAULT_NOTE_CONTAINER_STYLE },
    63→            fontColor: "#000000",
    64→            fontFamily: "inherit",
    65→        };
    66→
    67→        const updatedNotes = [...notes, newNote];
    68→        setNotes(updatedNotes);
    69→        setHasUnsavedChanges(true);
    70→    };
    71→
    72→    const handleUpdateContent = useCallback(
    73→        (noteId, content) => {
    74→            setNotes((prev) => {
    75→                let changed = false;
    76→                const updated = prev.map((n) => {
    77→                    if (n.id !== noteId) return n;
    78→                    if (n.content === content) return n;
    79→                    changed = true;
    80→                    return { ...n, content };
    81→                });
    82→                if (changed) setHasUnsavedChanges(true);
    83→                return updated;
    84→            });
    85→        },
    86→        []
    87→    );
    88→
    89→    const handleUpdateStyle = useCallback(
    90→        (noteId, styleData) => {
    91→            setNotes((prev) => {
    92→                const updated = prev.map((n) =>
    93→                    n.id === noteId
    94→                        ? {
    95→                              ...n,
    96→                              containerStyle: styleData.containerStyle,
    97→                              fontColor: styleData.fontColor,
    98→                              fontFamily: styleData.fontFamily,
    99→                          }
   100→                        : n
   101→                );
   102→                setHasUnsavedChanges(true);
   103→                return updated;
   104→            });
   105→        },
   106→        []
   107→    );
   108→
   109→    const handleDeleteNote = useCallback(
   110→        async (noteId) => {
   111→            const updated = notes
   112→                .filter((n) => n.id !== noteId)
   113→                .map((n, i) => ({ ...n, order: i }));
   114→
   115→            setNotes(updated);
   116→            const saved = await saveNotes(updated);
   117→            setHasUnsavedChanges(!saved);
   118→        },
   119→        [notes, saveNotes]
   120→    );
   121→
   122→    const handleSaveAll = useCallback(async () => {
   123→        const saved = await saveNotes(notes);
   124→        if (saved) {
   125→            setHasUnsavedChanges(false);
   126→        }
   127→        return saved;
   128→    }, [notes, saveNotes]);
   129→
   130→    const sortedNotes = [...notes].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
   131→
   132→    if (!isOwner && sortedNotes.length === 0) {
   133→        return null;
   134→    }
   135→
   136→    return (
   137→        <div className="profile-notes-section">
   138→            {isOwner && (
   139→                <div className="notes-actions">
   140→                    <button
   141→                        className="add-note-button"
   142→                        onClick={handleAddNote}
   143→                        disabled={notes.length >= MAX_NOTES_COUNT || isSaving}
   144→                    >
   145→                        <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 -960 960 960" width="18px" fill="currentColor">
   146→                            <path d="M440-440H200v-80h240v-240h80v240h240v80H520v240h-80v-240Z" />
   147→                        </svg>
   148→                        Add Note {notes.length > 0 && `(${notes.length}/${MAX_NOTES_COUNT})`}
   149→                    </button>
   150→                </div>
   151→            )}
   152→
   153→            {sortedNotes.length > 0 && (
   154→                <div className="notes-list">
   155→                    {sortedNotes.map((note) => (
   156→                        <NoteContainer
   157→                            key={note.id}
   158→                            note={note}
   159→                            isOwner={isOwner}
   160→                            expandInnerContainerOnClick={expandInnerContainerOnClick}
   161→                            onUpdateContent={(content) => handleUpdateContent(note.id, content)}
   162→                            onUpdateStyle={(styleData) => handleUpdateStyle(note.id, styleData)}
   163→                            onDelete={() => handleDeleteNote(note.id)}
   164→                            onSaveNotes={handleSaveAll}
   165→                            hasUnsavedChanges={hasUnsavedChanges}
   166→                            isSaving={isSaving}
   167→                        />
   168→                    ))}
   169→                </div>
   170→            )}
   171→
   172→            {isSaving && (
   173→                <div className="notes-saving-indicator">
   174→                    <svg xmlns="http://www.w3.org/2000/svg" height="12px" viewBox="0 -960 960 960" width="12px" fill="currentColor">
   175→                        <path d="M480-80q-83 0-156-31.5T197-197q-54-54-85.5-127T80-480q0-83 31.5-156T197-763q54-54 127-85.5T480-880q83 0 156 31.5T763-763q54 54 85.5 127T880-480q0 83-31.5 156T763-197q-54 54-127 85.5T480-80Z" />
   176→                    </svg>
   177→                    Saving...
   178→                </div>
   179→            )}
   180→        </div>
   181→    );
   182→};
   183→
   184→export default ProfileNotesSection;
   185→

