    15→        if (content) {
    16→            try {
    17→                const parsed = typeof content === "string" ? JSON.parse(content) : content;
    18→                const editorState = editor.parseEditorState(parsed);
    19→                editor.setEditorState(editorState);
    20→            } catch (err) {
    21→                console.error("Failed to load note content:", err);
    22→            }
    23→        }
    24→    }, [content, editor]);
    25→
    26→    return null;
    27→};
    28→
    29→const theme = {
    30→    paragraph: "editor-paragraph",
    31→    heading: {
    32→        h1: "editor-heading-h1",
    33→        h2: "editor-heading-h2",
    34→        h3: "editor-heading-h3",
    35→    },
    36→    quote: "editor-quote",
    37→    text: {
    38→        bold: "editor-text-bold",
    39→        italic: "editor-text-italic",
    40→        underline: "editor-text-underline",
    41→    },
    42→};
    43→
    44→const ReadOnlyNoteView = ({ content, expandInnerContainerOnClick = false }) => {
    45→    const contentEditableRef = useRef(null);
    46→
    47→    const initialConfig = {
    48→        namespace: "ReadOnlyNote",
    49→        editable: false,
    50→        nodes: [ImageNode, HeadingNode, QuoteNode, ContainerNode],
    51→        theme,
    52→        onError: (error) => console.error("ReadOnlyNote error:", error),
    53→    };
    54→
    55→    const collapseExpandedInnerContainers = useCallback(() => {
    56→        document
    57→            .querySelectorAll(".note-inner-container.is-visit-full-view")
    58→            .forEach((element) => element.classList.remove("is-visit-full-view"));
    59→        document.body.classList.remove("visit-note-fullview-active");
    60→    }, []);
    61→
    62→    const handleInnerContainerClick = useCallback(
    63→        (event) => {
    64→            if (!expandInnerContainerOnClick) return;
    65→
    66→            const rawTarget = event.target;
    67→            const targetElement =
    68→                rawTarget instanceof Element ? rawTarget : rawTarget?.parentElement || null;
    69→            if (!targetElement) return;
    70→
    71→            const targetContainer = targetElement.closest(".note-inner-container");
    72→            if (!targetContainer) return;
    73→
    74→            const shouldExpand = !targetContainer.classList.contains("is-visit-full-view");
    75→            collapseExpandedInnerContainers();
    76→
    77→            if (shouldExpand) {
    78→                targetContainer.classList.add("is-visit-full-view");
    79→                document.body.classList.add("visit-note-fullview-active");
    80→            }
    81→        },
    82→        [collapseExpandedInnerContainers, expandInnerContainerOnClick]
    83→    );
