   166→const LoadInitialContent = ({ initialContent }) => {
   167→    const [editor] = useLexicalComposerContext();
   168→    const hasLoaded = useRef(false);
   169→
   170→    useEffect(() => {
   171→        if (initialContent && !hasLoaded.current) {
   172→            hasLoaded.current = true;
   173→            try {
   174→                const parsed = typeof initialContent === "string" ? JSON.parse(initialContent) : initialContent;
   175→                const editorState = editor.parseEditorState(parsed);
   176→                editor.setEditorState(editorState);
   177→            } catch (err) {
   178→                console.error("Failed to load initial content:", err);
   179→            }
   180→        }
   181→    }, [initialContent, editor]);
   182→
   183→    return null;
   184→};
   185→
   186→const EnsureDefaultContainer = ({ initialContent }) => {
   187→    const [editor] = useLexicalComposerContext();
   188→    const hasEnsuredRef = useRef(false);
   189→
   190→    useEffect(() => {
   191→        if (initialContent || hasEnsuredRef.current) return;
   192→
   193→        editor.update(() => {
   194→            const root = $getRoot();
   195→            const children = root.getChildren();
   196→            const hasContainer = children.some((node) => node?.__type === "container");
   197→            if (hasContainer) return;
   198→
   199→            root.clear();
   200→            root.append($createContainerNode());
   201→            hasEnsuredRef.current = true;
   202→        });
   203→    }, [editor, initialContent]);
   204→
   205→    return null;
   206→};
   207→
   208→const InlineAddContainerButton = () => {
   209→    const [editor] = useLexicalComposerContext();
   210→
   211→    const handleInsertContainer = useCallback((e) => {
   212→        e.preventDefault();
   213→        e.stopPropagation();
   214→        editor.dispatchCommand(INSERT_CONTAINER_COMMAND, {});
   215→    }, [editor]);
   216→
   217→    return (
   218→        <button
   219→            type="button"
   220→            className="inline-note-add-container-btn"
   221→            onMouseDown={(e) => e.preventDefault()}
   222→            onClick={handleInsertContainer}
   223→            title="Add container"
   224→        >
   225→            + Container
   226→        </button>
   227→    );
   228→};
   229→
   230→const InlineNoteEditor = ({ initialContent, onSave, onExplicitSave, hasUnsavedChanges, isSaving }) => {
   231→    const debounceRef = useRef(null);
   232→    const editorShellRef = useRef(null);
   233→    const { session } = useAuth();
   234→    const [showInlineSaveButton, setShowInlineSaveButton] = useState(false);
   235→
   236→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
   237→    const addUploadedImagePath = useCallback((imagePath) => {
   238→        setUploadedImagePaths((prev) => [...prev, imagePath]);
   239→    }, []);
   240→
   241→    // Expose session and addUploadedImagePath to ContainerNode via window globals
   242→    useEffect(() => {
   243→        window.__notesEditorSession = session;
   244→        window.__notesEditorAddImagePath = addUploadedImagePath;
   245→        return () => {
   246→            delete window.__notesEditorSession;
   247→            delete window.__notesEditorAddImagePath;
   248→        };
   249→    }, [session, addUploadedImagePath]);
   250→
   251→    const initialConfig = {
   252→        namespace: "InlineNote",
   253→        editable: true,
   254→        nodes: [ImageNode, HeadingNode, QuoteNode, ContainerNode],
   255→        theme,
   256→        onError: (error) => console.error("InlineNote error:", error),
   257→    };
   258→
   259→    const handleChange = useCallback(
   260→        (editorState) => {
   261→            const jsonStr = JSON.stringify(editorState.toJSON());
   262→
   263→            if (debounceRef.current) {
   264→                clearTimeout(debounceRef.current);
   265→            }
   266→
   267→            debounceRef.current = setTimeout(() => {
   268→                if (onSave) onSave(jsonStr);
   269→            }, 1500);
   270→        },
   271→        [onSave]
   272→    );
   273→
   274→    useEffect(() => {
   275→        return () => {
   276→            if (debounceRef.current) clearTimeout(debounceRef.current);
   277→        };
   278→    }, []);
   279→
   280→    useEffect(() => {
   281→        const handleOutsideClick = (e) => {
   282→            if (!editorShellRef.current?.contains(e.target)) {
   283→                setShowInlineSaveButton(false);
   284→            }
   285→        };
   286→
   287→        document.addEventListener("mousedown", handleOutsideClick);
   288→        return () => document.removeEventListener("mousedown", handleOutsideClick);
   289→    }, []);
   290→
   291→    const handleInlineSave = useCallback(async () => {
   292→        if (!onExplicitSave) return;
   293→        const saved = await onExplicitSave();
   294→        if (saved) {
   295→            setShowInlineSaveButton(false);
   296→        }
   297→    }, [onExplicitSave]);
   298→
   299→    return (
   300→        <div className="inline-note-editor-wrapper">
   301→            <LexicalComposer initialConfig={initialConfig}>
   302→                <div className="inline-note-editor-shell" ref={editorShellRef}>
   303→                    <RichTextPlugin
   304→                        contentEditable={
   305→                            <div className="inline-note-content-editable-container">
   306→                                <ContentEditable
   307→                                    className={`inline-note-content-editable${showInlineSaveButton ? " with-inline-save" : ""}`}
   308→                                    onFocus={() => setShowInlineSaveButton(true)}
   309→                                    onClick={() => setShowInlineSaveButton(true)}
   310→                                />
   311→                                {showInlineSaveButton && <InlineAddContainerButton />}
   312→                                {showInlineSaveButton && onExplicitSave && (
   313→                                    <button
   314→                                        type="button"
   315→                                        className="inline-note-inline-save-btn"
   316→                                        onMouseDown={(e) => e.preventDefault()}
   317→                                        onClick={handleInlineSave}
   318→                                        disabled={isSaving || !hasUnsavedChanges}
   319→                                    >
   320→                                        {isSaving ? "Saving..." : hasUnsavedChanges ? "Save Notes" : "Saved"}
   321→                                    </button>
   322→                                )}
   323→                            </div>
   324→                        }
   325→                        placeholder={<div className="inline-note-placeholder">Write something...</div>}
   326→                        ErrorBoundary={LexicalErrorBoundary}
   327→                    />
   328→                    <ImagePlugin addUploadedImagePath={addUploadedImagePath} />
   329→                    <ContainerPlugin />
   330→                    <HistoryPlugin />
   331→                    <OnChangePlugin onChange={handleChange} />
   332→                </div>
   333→                <LoadInitialContent initialContent={initialContent} />
   334→                <EnsureDefaultContainer initialContent={initialContent} />
   335→            </LexicalComposer>
   336→        </div>
   337→    );
   338→};
   339→
   340→export default InlineNoteEditor;
